operation.add:
// PC Configurator
if ($this->user->hasPermission('access', 'extension/module/configurator')) {
	$data['menus'][] = array(
		'id'       => 'menu-configurator',
		'icon'	   => 'fa-cogs',
		'name'	   => 'კონფიგურატორი',
		'href'     => $this->url->link('extension/module/configurator', 'user_token=' . $this->session->data['user_token'], true),
		'children' => array()
	);
}
